-- ── スキーマ ─────────────────────────────────────
-- ログイン機能削除、DBを問題文の格納専用に変更
CREATE TABLE IF NOT EXISTS sudoku_problems (
  problem_id   INTEGER PRIMARY KEY AUTOINCREMENT,
  difficulty   TEXT    NOT NULL,
  problem_data TEXT    NOT NULL,
  answer_data  TEXT    NOT NULL
);

